/** UsptCnvnSclpstHistDao.insert */
insert into uspt_cnvn_sclpst_hist (
			 cnvn_sclpst_hist_id
			,cnvn_change_req_id
			,confm_cnvn_sclpst_hist_id
			,indvdl_bsnm_div_cd
			,nm
			,gender_cd
			,enc_mbtlnum
			,native
			,enc_email
			,enc_brthdy
			,bsnm_nm
			,bizrno
			,ceo_nm
			,charger_nm
			,charger_mbtlnum
			,charger_email
			,creator_id
			,created_dt
		) values (
			 #{cnvnSclpstHistId}
			,#{cnvnChangeReqId}
			,#{confmCnvnSclpstHistId}
			,#{indvdlBsnmDivCd}
			,#{nm}
			,#{genderCd}
			,#{encMbtlnum}
			,#{NativeYn}
			,#{encEmail}
			,#{encBrthdy}
			,#{bsnmNm}
			,#{bizrno}
			,#{ceoNm}
			,#{chargerNm}
			,#{chargerMbtlnum}
			,#{chargerEmail}
			,#{creatorId}
			,#{createdDt}
		)
